import{_ as a,o as e,c as o,ag as s}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"AI Chat (Runbook Assistant)","description":"Describe what you need in plain language and the AI assistant selects and executes the right runbook.","frontmatter":{"title":"AI Chat (Runbook Assistant)","description":"Describe what you need in plain language and the AI assistant selects and executes the right runbook."},"headers":[],"relativePath":"portals/runbook/ai-chat.md","filePath":"portals/runbook/ai-chat.md"}'),n={name:"portals/runbook/ai-chat.md"};function i(r,t,h,c,l,u){return e(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="ai-chat-runbook-assistant" tabindex="-1">AI Chat (Runbook Assistant) <a class="header-anchor" href="#ai-chat-runbook-assistant" aria-label="Permalink to &quot;AI Chat (Runbook Assistant)&quot;">​</a></h1><p><strong>Route:</strong> <code>/rb/chat</code> · <strong>Edition:</strong> Pro+</p><p>The AI Chat lets you describe what you need in plain language and the assistant selects the most appropriate runbook and executes it — or walks you through the steps interactively.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><ol><li>Type your query (e.g. &quot;check the health of the payments service&quot;)</li><li>The assistant searches all runbooks by name, description, and tags using an LLM</li><li>It shows the best matching runbook with a confidence explanation</li><li>You can confirm execution or ask for a different runbook</li></ol><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>AI Chat uses the OpenAI connection from <strong>Portal Config → AI Settings</strong>. If no AI config is present, the Chat tab is disabled.</p><h2 id="session-history" tabindex="-1">Session history <a class="header-anchor" href="#session-history" aria-label="Permalink to &quot;Session history&quot;">​</a></h2><p>Each conversation is a session. Previous messages in the session are included in context so the assistant can refer back to earlier results when you ask follow-up questions.</p>',9)])])}const b=a(n,[["render",i]]);export{p as __pageData,b as default};
